def spiral_traverse(grid):
    out = []
    if not grid or not grid[0]:
        return out
    top, bot = 0, len(grid) - 1
    left, right = 0, len(grid[0]) - 1
    while top <= bot and left <= right:
        for c in range(left, right + 1):
            out.append(grid[top][c])
        for r in range(top + 1, bot + 1):
            out.append(grid[r][right])
        if top < bot and left < right:
            for c in range(right - 1, left - 1, -1):
                out.append(grid[bot][c])
            for r in range(bot - 1, top, -1):
                out.append(grid[r][left])
        top += 1; bot -= 1; left += 1; right -= 1
    return out

